#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int64_t F(int s, int x) {
    if (s < x) return 0;
    if (s == x) return 1;
    int64_t res = 0;
    for (int i = 0; i <= s; i++) {
        for (int j = 0; j <= s; j++) {
            int k = s - i - j;
            if (k < 0) continue;
            if ((i ^ j ^ k) == x) res++;
        }
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b;
        int64_t N;
        scanf("%d %d %lld", &a, &b, &N);
        int64_t res = 0;
        for (int64_t n = 1; n <= N; n++) {
            res = (res + F(a * n, b * n)) % MOD;
        }
        printf("%lld\n", res);
    }
    return 0;
}

